INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a1a1a1a1-1111-1111-1111-111111111111', NOW(), NOW(), 'The Age of Invisible Computers', 'Curio Tech', 'https://example.com/art-001', '2026-04-25T00:00:00Z', 'The Age of Invisible Computers', 'invisible-computers', 'd1c1c1c1-1111-1111-1111-111111111111', '2026-04-25T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=400', 'Technology is disappearing into the background of our lives — and that might change everything.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c1c1c1c1-1111-1111-1111-111111111111', NOW(), NOW(), 'MEDIUM', 'There was a time when computers were room-sized machines that only scientists could operate. Then they shrank to desktops, then laptops, then phones. Now, they are {{ambient}}—woven into the fabric of everyday life in ways we rarely notice.\n\nSmart thermostats learn your schedule. Your car adjusts its mirrors automatically. Your headphones sense when you put them down and pause the music. Computing has become {{ubiquitous}}, but its interfaces have nearly vanished.\n\nThis is the promise of ambient computing: technology that serves you without demanding your attention. The goal is a {{seamless}} experience where the digital and physical worlds merge so gracefully that the boundary between them disappears.\n\nBut this transformation comes with questions. When sensors are {{embedded}} in every surface, who owns the data they collect? When every interaction is monitored to reduce {{latency}} and improve predictions, what happens to privacy?\n\nThe invisible computer is powerful precisely because it is invisible. That invisibility is both its greatest feature and its most significant risk.', NULL, 'a1a1a1a1-1111-1111-1111-111111111111')
