(uuid_generate_v4(), NOW(), NOW(), 'embedded', 'Fixed firmly and deeply within a surrounding environment.', 'The sensor is embedded in the wall and invisible to users.', 'c1c1c1c1-1111-1111-1111-111111111111'),
