(uuid_generate_v4(), NOW(), NOW(), 'melatonin', 'A hormone produced by the brain that regulates sleep-wake cycles.', 'Darkness triggers the release of melatonin in the brain.', 'c2c2c2c2-2222-2222-2222-222222222222'),
(uuid_generate_v4(), NOW(), NOW(), 'cumulative', 'Increasing or growing by successive additions over time.', 'The cumulative effect of poor sleep can harm your health.', 'c2c2c2c2-2222-2222-2222-222222222222'),
