INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a4a4a4a4-4444-4444-4444-444444444444', NOW(), NOW(), 'What Jazz Invented That We Still Use Today', 'Culture Weekly', 'https://example.com/art-004', '2026-04-21T00:00:00Z', 'What Jazz Invented That We Still Use Today', 'jazz-innovation', 'd1c1c1c1-4444-4444-4444-444444444444', '2026-04-21T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1511192336575-5a79af67a629?q=80&w=400', 'The improvisational logic of jazz didn''t stay in music. It spread into architecture, software, and how we think about creativity.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c4c4c4c4-4444-4444-4444-444444444444', NOW(), NOW(), 'MEDIUM', 'When jazz emerged in New Orleans in the early twentieth century, critics called it noise. Within a decade, it had changed how the world thought about music. Within a half-century, its logic had spread far beyond music altogether.\n\nThe central innovation of jazz was {{improvisation}}. Unlike classical music, where performers execute a fixed score, jazz musicians create in real time, responding to each other''s choices. Structure exists—harmonies, progressions, the form of the song—but within it, everything is negotiated live.\n\n{{Syncopation}} was the sonic signature of this approach: placing rhythmic emphasis where it wasn''t expected, creating tension and release that felt viscerally different from anything before it.\n\nWhat jazz musicians were doing, philosophers and theorists would later {{codify}} as a model for collaborative creativity. The jazz ensemble became a metaphor for high-functioning teams: individuals with deep expertise, a shared framework, and the freedom to contribute within it.\n\nThis jazz {{vernacular}} entered architecture, software development, and even military strategy. The idea that a {{canonical}} form can enable rather than constrain creativity—that you can have both structure and spontaneity—is one of jazz''s most enduring gifts.', NULL, 'a4a4a4a4-4444-4444-4444-444444444444')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'improvisation', 'Creating and performing spontaneously, without prior preparation.', 'Jazz musicians are celebrated for their skill at improvisation.', 'c4c4c4c4-4444-4444-4444-444444444444'),
(uuid_generate_v4(), NOW(), NOW(), 'syncopation', 'A musical rhythm that emphasizes the normally weak beat.', 'The drummer''s syncopation gave the song unexpected energy.', 'c4c4c4c4-4444-4444-4444-444444444444'),
(uuid_generate_v4(), NOW(), NOW(), 'canonical', 'Conforming to an accepted standard; widely recognized.', 'Miles Davis''s Kind of Blue is considered a canonical jazz album.', 'c4c4c4c4-4444-4444-4444-444444444444'),
(uuid_generate_v4(), NOW(), NOW(), 'vernacular', 'A style or manner particular to a specific group or time.', 'The building used a local vernacular style with brick and clay.', 'c4c4c4c4-4444-4444-4444-444444444444'),
(uuid_generate_v4(), NOW(), NOW(), 'codify', 'To arrange something into a systematic set of rules.', 'The team tried to codify their creative process into a framework.', 'c4c4c4c4-4444-4444-4444-444444444444');
INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a5a5a5a5-5555-5555-5555-555555555555', NOW(), NOW(), 'The Attention Economy Has a New Villain', 'Tech Insider', 'https://example.com/art-005', '2026-04-20T00:00:00Z', 'The Attention Economy Has a New Villain', 'attention-economy', 'd1c1c1c1-1111-1111-1111-111111111111', '2026-04-20T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?q=80&w=400', 'For years we blamed the algorithm. A new wave of research is pointing somewhere more uncomfortable.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c5c5c5c5-5555-5555-5555-555555555555', NOW(), NOW(), 'MEDIUM', 'For most of the past decade, the {{algorithm}} was cast as the villain of the attention economy. The feeds that kept us scrolling were, we were told, the product of optimization systems designed to maximize engagement at any cost.\n\nThat story was useful, and partly true. But new research is complicating it.\n\nStudies from behavioral economists suggest that {{compulsive}} phone use is less about algorithmic manipulation and more about the underlying reward structure that humans bring to the device. The {{dopamine}} hit from a new notification isn''t manufactured by an engineer; it''s a feature of how human motivation has always worked, now pointed at a device that delivers rewards at superhuman speed.\n\nThis changes how we think about solutions. If the problem were purely algorithmic, the fix would be regulation: force platforms to add {{friction}}, limit recommendation systems, require chronological feeds.\n\nBut if the problem is partly human—if we are, in some sense, exploiting ourselves—then the solution requires something harder to legislate: a meaningful restoration of {{autonomy}} over how we spend our attention.\n\nThe algorithm didn''t invent distraction. It just made it much, much easier.', NULL, 'a5a5a5a5-5555-5555-5555-555555555555')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'algorithm', 'A set of rules a computer follows to solve a problem or make decisions.', 'The recommendation algorithm shows content based on your history.', 'c5c5c5c5-5555-5555-5555-555555555555'),
(uuid_generate_v4(), NOW(), NOW(), 'compulsive', 'Resulting from an irresistible urge; done repeatedly and without control.', 'The compulsive need to check notifications disrupts focus.', 'c5c5c5c5-5555-5555-5555-555555555555'),
(uuid_generate_v4(), NOW(), NOW(), 'dopamine', 'A brain chemical linked to pleasure and reward-seeking behavior.', 'Likes and comments trigger dopamine responses in the brain.', 'c5c5c5c5-5555-5555-5555-555555555555'),
(uuid_generate_v4(), NOW(), NOW(), 'friction', 'In design, intentional resistance that slows down certain user actions.', 'Adding friction to checkout reduced impulsive purchases.', 'c5c5c5c5-5555-5555-5555-555555555555'),
(uuid_generate_v4(), NOW(), NOW(), 'autonomy', 'The right and ability to make your own independent choices.', 'Users want more autonomy over what their feed shows them.', 'c5c5c5c5-5555-5555-5555-555555555555');
INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a6a6a6a6-6666-6666-6666-666666666666', NOW(), NOW(), 'The Trees That Talk Underground', 'Nature Science', 'https://example.com/art-006', '2026-04-19T00:00:00Z', 'The Trees That Talk Underground', 'talking-trees', 'd1c1c1c1-2222-2222-2222-222222222222', '2026-04-19T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?q=80&w=400', 'Forests communicate through a network of fungi — and new research suggests they do so with surprising sophistication.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c6c6c6c6-6666-6666-6666-666666666666', NOW(), NOW(), 'MEDIUM', 'Beneath any old-growth forest floor lies a network that ecologists have called the "wood wide web"—a vast web of {{mycorrhizal}} fungi connecting tree roots across hundreds of meters.\n\nThe relationship between trees and fungi is one of {{symbiosis}}: the fungi receive sugars that the trees produce through {{photosynthesis}}, and in exchange, dramatically increase the trees'' ability to absorb water and {{nutrient}} from the soil.\n\nBut recent research suggests the exchange is more complex than a simple transaction. Older "mother trees" appear to send more carbon to younger seedlings growing in their shade—trees that cannot yet perform enough photosynthesis to sustain themselves. The support appears {{reciprocal}}: seedlings that are helped tend to root into the network and contribute as they mature.\n\nWhat is driving this? Is it kin recognition—trees preferentially supporting their own offspring? Is it simply the physics of how carbon moves through a network? Researchers are divided.\n\nWhat is less contested is the practical implication: healthy mycorrhizal networks make forests more resilient. Logging practices that sever these connections, or replanting programs using a single species, can disrupt the underground infrastructure forests depend on to survive drought and disease.', NULL, 'a6a6a6a6-6666-6666-6666-666666666666')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'mycorrhizal', 'Relating to a symbiotic relationship between fungi and plant roots.', 'Mycorrhizal networks allow trees to share nutrients underground.', 'c6c6c6c6-6666-6666-6666-666666666666'),
(uuid_generate_v4(), NOW(), NOW(), 'symbiosis', 'A close interaction between two organisms that benefits both parties.', 'The flowers and bees exist in a symbiosis that benefits both.', 'c6c6c6c6-6666-6666-6666-666666666666'),
(uuid_generate_v4(), NOW(), NOW(), 'photosynthesis', 'The process by which plants use sunlight to produce food.', 'Seedlings in deep shade cannot perform sufficient photosynthesis.', 'c6c6c6c6-6666-6666-6666-666666666666'),
(uuid_generate_v4(), NOW(), NOW(), 'nutrient', 'A substance that nourishes living things and supports growth.', 'The fungi transport carbon and nutrients between trees.', 'c6c6c6c6-6666-6666-6666-666666666666'),
(uuid_generate_v4(), NOW(), NOW(), 'reciprocal', 'Given or felt by each toward the other; mutual.', 'The relationship between trees and fungi is reciprocal.', 'c6c6c6c6-6666-6666-6666-666666666666');
INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a7a7a7a7-7777-7777-7777-777777777777', NOW(), NOW(), 'Why Luxury Brands Refuse to Go on Sale', 'Luxury Insight', 'https://example.com/art-007', '2026-04-18T00:00:00Z', 'Why Luxury Brands Refuse to Go on Sale', 'luxury-brands', 'd1c1c1c1-3333-3333-3333-333333333333', '2026-04-18T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1548036328-c9fa89d128fa?q=80&w=400', 'There''s a reason a Hermès bag never appears in a Black Friday email. It''s not snobbery — it''s economics.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c7c7c7c7-7777-7777-7777-777777777777', NOW(), NOW(), 'MEDIUM', 'In 2021, Burberry destroyed £28 million worth of unsold inventory rather than discount it. This was not a mistake. It was a strategy.\n\nLuxury economics operates on a principle that inverts normal market logic. For most goods, lower prices increase demand. For luxury goods, lower prices can destroy it. The value of a luxury product is partly its {{scarcity}} and partly its {{prestige}}—and both are undermined by ubiquity and discounting.\n\nA luxury bag is not just a bag. It is a signal. When you carry it, you communicate something: purchasing power, taste, membership in a certain stratum. That signal depends entirely on the bag being difficult to obtain.\n\nUnlike most goods, which suffer {{depreciation}} the moment they leave the store, well-maintained luxury goods often appreciate. A classic Hermès Birkin has outperformed many stock indices over the past two decades. This investment logic makes the brands more {{aspirational}}, which in turn justifies higher prices.\n\nThe strategy requires iron discipline. One sale, one warehouse outlet, one significant markdown, and the illusion cracks. Discounting signals desperation, and desperation would {{dilute}} the one thing luxury brands truly sell: the perception of limitless demand.\n\nBurning the product is cheaper.', NULL, 'a7a7a7a7-7777-7777-7777-777777777777')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'scarcity', 'The state of being scarce or in short supply.', 'Artificial scarcity keeps the price of limited-edition sneakers high.', 'c7c7c7c7-7777-7777-7777-777777777777'),
(uuid_generate_v4(), NOW(), NOW(), 'prestige', 'Widespread respect and admiration associated with quality or exclusivity.', 'The brand''s prestige depends entirely on its exclusivity.', 'c7c7c7c7-7777-7777-7777-777777777777'),
(uuid_generate_v4(), NOW(), NOW(), 'depreciation', 'A reduction in the value of something over time.', 'Unlike most goods, some luxury items have negative depreciation.', 'c7c7c7c7-7777-7777-7777-777777777777'),
(uuid_generate_v4(), NOW(), NOW(), 'aspirational', 'Appealing to social ambition; representing a desired status.', 'The campaign was aspirational, showing the bag in elite settings.', 'c7c7c7c7-7777-7777-7777-777777777777'),
(uuid_generate_v4(), NOW(), NOW(), 'dilute', 'To weaken something by reducing its quality or concentration.', 'Putting products on sale can dilute a brand''s premium image.', 'c7c7c7c7-7777-7777-7777-777777777777');
INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a8a8a8a8-8888-8888-8888-888888888888', NOW(), NOW(), 'The Art That Was Never Meant to Be Seen', 'History Daily', 'https://example.com/art-008', '2026-04-17T00:00:00Z', 'The Art That Was Never Meant to Be Seen', 'unseen-art', 'd1c1c1c1-4444-4444-4444-444444444444', '2026-04-17T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1544413647-79f0447947c2?q=80&w=400', 'For centuries, craftsmen carved intricate details into cathedral ceilings too high for any visitor to see. What does that tell us?')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c8c8c8c8-8888-8888-8888-888888888888', NOW(), NOW(), 'MEDIUM', 'High on the ceiling of many medieval cathedrals, in the shadowed spaces above the vaulted arches, there are {{intricate}} carvings that no visitor has ever clearly seen. The men who made them worked by candlelight, in difficult conditions, on details that would be invisible to every human eye below.\n\nNo one required this level of care. There were no quality inspectors for the roofline of a twelfth-century church. Yet the work was done with the same precision as the altar carvings visible to every worshipper.\n\nThe obvious explanation is religious: God could see the unseen work. But scholars note that many of these craftsmen were {{secular}} workers—paid laborers, not monks or mystics.\n\nA second explanation may be more interesting: that the medieval concept of craft involved an idea of {{transcendence}} through excellence. The work was good because it had to be good. The carver''s identity was {{anonymous}}, their name unrecorded, yet the work carried its own meaning.\n\nWhat this challenges is a modern assumption: that quality requires an audience. We tend to produce work relative to how we will be perceived. The cathedral carvers suggest a different logic—that some value is {{intrinsic}}, that the unseen can still matter, and that excellence pursued privately might be the most honest kind.', NULL, 'a8a8a8a8-8888-8888-8888-888888888888')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'intricate', 'Very complicated or detailed in design or structure.', 'The intricate carvings took years to complete.', 'c8c8c8c8-8888-8888-8888-888888888888'),
(uuid_generate_v4(), NOW(), NOW(), 'secular', 'Not connected to religious or spiritual matters; worldly.', 'The museum houses both secular and religious art.', 'c8c8c8c8-8888-8888-8888-888888888888'),
(uuid_generate_v4(), NOW(), NOW(), 'transcendence', 'The quality of exceeding ordinary limits; spiritual elevation.', 'Medieval builders sought transcendence through extreme height and light.', 'c8c8c8c8-8888-8888-8888-888888888888'),
