INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a2a2a2a2-2222-2222-2222-222222222222', NOW(), NOW(), 'Why Your Brain Needs More Darkness', 'Nature Health', 'https://example.com/art-002', '2026-04-23T00:00:00Z', 'Why Your Brain Needs More Darkness', 'brain-darkness', 'd1c1c1c1-2222-2222-2222-222222222222', '2026-04-23T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1532938911079-1b06ac7ceec7?q=80&w=400', 'Light pollution isn''t just an astronomy problem — it may be quietly disrupting human health at a cellular level.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c2c2c2c2-2222-2222-2222-222222222222', NOW(), NOW(), 'MEDIUM', 'Every cell in your body contains a tiny clock. These clocks run on a {{circadian}} rhythm—a roughly 24-hour cycle that governs when you feel awake, when you get hungry, and when you heal. For most of human history, darkness was the signal that told those clocks to wind down.\n\nThat signal is disappearing. Artificial light is now so prevalent that two-thirds of the world''s population cannot see the Milky Way at night. This is called light pollution, and its effects go far beyond ruined stargazing.\n\nWhen you are exposed to bright light at night, your brain delays the release of {{melatonin}}, the hormone that prepares your body for sleep. The disruption is subtle but {{cumulative}}. Over weeks and months, it can interfere with metabolism, immune function, and mood.\n\nBlue light—emitted by phones and screens—is particularly effective at suppressing melatonin. Research shows it can {{suppress}} melatonin production for up to three hours after exposure, pushing your sleep window back and reducing quality even when you do eventually rest.\n\nThe {{prevalence}} of sleep problems in modern societies may be, at least in part, a light problem. The fix sounds simple: more darkness. In practice, it requires rethinking how we design our cities, our homes, and our evenings.', NULL, 'a2a2a2a2-2222-2222-2222-222222222222')
