(uuid_generate_v4(), NOW(), NOW(), 'cumulative', 'Increasing or growing by successive additions over time.', 'The cumulative effect of poor sleep can harm your health.', 'c2c2c2c2-2222-2222-2222-222222222222'),
(uuid_generate_v4(), NOW(), NOW(), 'suppress', 'To prevent something from happening or being expressed.', 'Bright light can suppress the production of sleep hormones.', 'c2c2c2c2-2222-2222-2222-222222222222'),
(uuid_generate_v4(), NOW(), NOW(), 'prevalence', 'The fact or condition of being widespread.', 'The prevalence of screen use has increased in recent decades.', 'c2c2c2c2-2222-2222-2222-222222222222');
