INSERT INTO articles (id, created_at, updated_at, original_title, source_name, source_url, original_published_at, title, slug, category_id, published_at, status, thumbnail_url, original_content) VALUES
('a3a3a3a3-3333-3333-3333-333333333333', NOW(), NOW(), 'The Hidden Economics of Your Morning Coffee', 'Global Finance', 'https://example.com/art-003', '2026-04-22T00:00:00Z', 'The Hidden Economics of Your Morning Coffee', 'coffee-economics', 'd1c1c1c1-3333-3333-3333-333333333333', '2026-04-22T00:00:00Z', 'PUBLISHED', 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?q=80&w=400', 'From Ethiopian highlands to your cup — a global commodity chain shaped by weather, politics, and a century of financial engineering.')
INSERT INTO article_contents (id, created_at, updated_at, level, content, audio_url, article_id) VALUES
('c3c3c3c3-3333-3333-3333-333333333333', NOW(), NOW(), 'MEDIUM', 'Coffee is the world''s second most traded {{commodity}} after oil. Each morning, hundreds of millions of people participate in a global market whose complexity would astonish them.\n\nThe price you pay at your local café reflects decisions made by farmers in Ethiopia and Brazil, traders in New York and London, and financial instruments developed over a century of {{volatility}} management.\n\nCoffee prices swing dramatically based on weather. A frost in Brazil can double futures prices overnight. This volatility invites {{speculation}}: hedge funds and commodity traders bet on price movements, sometimes amplifying the very swings they claim to be managing.\n\nMeanwhile, the farmers at the beginning of this chain earn the smallest slice of the value. In a $5 cup of coffee, the grower typically receives less than five cents. The rest is absorbed by processing, shipping, roasting, branding, and retail {{margin}}.\n\nSome producers {{hedge}} their exposure by selling forward contracts—locking in a price before harvest. But this protection cuts both ways: if prices rise dramatically, they miss the upside. If prices fall, they are protected, but only until the contract expires.\n\nThe next time you hold a warm cup, consider the system that produced it: fragile, interconnected, and wildly underappreciated.', NULL, 'a3a3a3a3-3333-3333-3333-333333333333')
INSERT INTO vocabularies (id, created_at, updated_at, word, definition, example_sentence, article_content_id) VALUES
(uuid_generate_v4(), NOW(), NOW(), 'commodity', 'A raw material or agricultural product that can be bought and sold.', 'Oil is one of the world''s most traded commodities.', 'c3c3c3c3-3333-3333-3333-333333333333'),
(uuid_generate_v4(), NOW(), NOW(), 'volatility', 'Tendency to change rapidly and unpredictably.', 'Currency volatility makes international trade riskier.', 'c3c3c3c3-3333-3333-3333-333333333333'),
(uuid_generate_v4(), NOW(), NOW(), 'speculation', 'Engaging in risky financial transactions hoping to profit from price changes.', 'Speculation in housing markets contributed to the 2008 crisis.', 'c3c3c3c3-3333-3333-3333-333333333333'),
(uuid_generate_v4(), NOW(), NOW(), 'margin', 'The amount by which revenue exceeds costs; profit earned.', 'The café operates on thin margins despite high prices.', 'c3c3c3c3-3333-3333-3333-333333333333'),
